def _backup(path: Path) -> str | None:
    if not path.exists():
        return None
    BACKUP.mkdir(parents=True, exist_ok=True)
    try:
        rel = path.relative_to(ROOT).as_posix().replace("/", "__")
    except ValueError:
        rel = path.name
    target = BACKUP / (rel + ".before_" + PATCH_ID)
    target.parent.mkdir(parents=True, exist_ok=True)
    if not target.exists():
        shutil.copy2(path, target)
    return str(target)
def _write(rel: str, text: str) -> dict:
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    existed = path.exists()
    backup = _backup(path)
    old = path.read_text(encoding="utf-8", errors="ignore") if existed else ""
    mutated = old != text
    if mutated:
        path.write_text(text, encoding="utf-8", newline="\n")
    return {"path": rel, "existed_before": existed, "mutated": mutated, "backup_path": backup}

def _append(rel: str, marker: str, text: str) -> dict:
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    existed = path.exists()
    backup = _backup(path)
    old = path.read_text(encoding="utf-8", errors="ignore") if existed else ""
    if marker in old:
        return {"path": rel, "existed_before": existed, "mutated": False, "backup_path": backup}
    path.write_text(old.rstrip() + "\n\n" + text.lstrip(), encoding="utf-8", newline="\n")
    return {"path": rel, "existed_before": existed, "mutated": True, "backup_path": backup}

def _ensure_text(rel: str, needle: str) -> dict:
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    existed = path.exists()
    backup = _backup(path)
    old = path.read_text(encoding="utf-8", errors="ignore") if existed else ""
    if needle in old:
        return {"path": rel, "existed_before": existed, "mutated": False, "backup_path": backup}
    addition = "\nrem " + needle + "\n"
    path.write_text(old.rstrip() + addition, encoding="utf-8", newline="\n")
    return {"path": rel, "existed_before": existed, "mutated": True, "backup_path": backup}

def _replace_text(rel: str, replacements: dict[str, str]) -> dict:
    path = ROOT / rel
    existed = path.exists()
    backup = _backup(path)
    old = path.read_text(encoding="utf-8", errors="ignore") if existed else ""
    new = old
    for a, b in replacements.items():
        new = new.replace(a, b)
    if new != old:
        path.write_text(new, encoding="utf-8", newline="\n")
    return {"path": rel, "existed_before": existed, "mutated": new != old, "backup_path": backup}

